const body = $input.first().json.body || {};
const confirm = String(body.confirm || '').trim().toLowerCase();
const operator = String(body.operator || 'unknown').trim();
if (confirm !== 'RESET') {
  return [{ json: { ok: false, error: "Missing confirmation. Send {\"confirm\":\"RESET\"}.", operator } }];
}
return [{ json: { ok: true, operator } }];

const resp = $input.first().json;
const errors = resp.errors || [];
if (errors.length) {
  return [{ json: { success: false, error: errors[0].message } }];
}
const results = resp.results || [];
let nodeCount = null;
if (results[2] && results[2].data && results[2].data[0]) nodeCount = results[2].data[0].row[0];
return [{ json: { success: true, node_count: nodeCount, operator: $('Validate Reset').first().json.operator, message: `Graph reset complete. Demo topology restored${nodeCount !== null ? ` (${nodeCount} nodes)` : ''}.` } }];
